import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, Grid } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface AlertCategory {
  type: string;
  count: number;
}

interface UnreadAlertsData {
  unreadAlerts: {
    total: number;
    categories: AlertCategory[];
  };
}

export default function Widget() {
  const alertData = response.data as UnreadAlertsData;
  const { total, categories } = alertData.unreadAlerts;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#2C2C2C' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FFC107', mb: 1 }}>
              Unread Alerts
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FF5722' }}>
              {total}
            </Typography>
          </Box>

          <PieChart
            height={120}
            series={[
              {
                data: categories.map(category => category.count),
                color: ['#FF5722', '#FFC107', '#4CAF50', '#2196F3', '#FF9800'],
                labels: categories.map(category => category.type),
              },
            ]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiPieElement-root': {
                stroke: '#2C2C2C',
                strokeWidth: 2,
              },
            }}
          />

          <Grid container spacing={1}>
            {categories.map((category, index) => (
              <Grid item xs={6} key={index}>
                <Chip
                  label={`${category.type}: ${category.count}`}
                  sx={{ width: '100%', fontSize: '11px', bgcolor: '#424242', color: 'white' }}
                />
              </Grid>
            ))}
          </Grid>
        </Stack>
      </CardContent>
    </Card>
  );
}
